APP_DIR="{{APP_DIR}}"
APP_LOG_DIR="{{APP_LOG_DIR}}"

APP_BASE="$(basename "${APP_DIR}")"
APP_PARENT="$(dirname "${APP_DIR}")"
APP_OLD="${APP_PARENT}/${APP_BASE}_OLD"
APP_TMP="${APP_PARENT}/${APP_BASE}_TMP"

echo "[INFO] APP_DIR     : ${APP_DIR}"
echo "[INFO] APP_OLD     : ${APP_OLD}"
echo "[INFO] APP_TMP     : ${APP_TMP}"
