step_verify_paths() {
  echo "[1] Weryfikacja katalogów..."
  local missing=0

  for d in "${APP_DIR}" "${APP_OLD}"; do
    if [[ -d "$d" ]]; then
      echo "    [OK] $d"
    else
      echo "    [ERROR] Brak katalogu: $d"
      missing=1
    fi
  done

  [[ "$missing" -eq 0 ]]
}

step_clear_logs() {
  echo "[2] Czyszczenie katalogu logów..."
  if [[ -d "${APP_LOG_DIR}" ]]; then
    echo "    Czyszczę: ${APP_LOG_DIR}"
    rm -rf "${APP_LOG_DIR:?}/"* || true
  else
    echo "    [WARN] Katalog logów nie istnieje: ${APP_LOG_DIR}"
  fi
}

step_cleanup_tmp() {
  echo "[3] Sprzątanie starego katalogu TMP..."
