    rm -rf "${APP_TMP}"
  else
    echo "    [INFO] Brak starego TMP: ${APP_TMP}"
  fi
}

step_swap_dirs() {
  echo "[4] Zamiana katalogów miejscami..."
  mv "${APP_DIR}" "${APP_TMP}"
  mv "${APP_OLD}" "${APP_DIR}"
  mv "${APP_TMP}" "${APP_OLD}"
  echo "    [OK] Zamiana zakończona sukcesem."
}

step_summary() {
